DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'shopendoftime' AND column_name = 'endoftime') THEN EXECUTE 'COMMENT ON COLUMN shopendoftime.endoftime IS ''该天班次的数据是否已结束营业日： 对于门店:    (0=没结束营业 1=已结束营业 2=已结束营业但:超时门店上传A服务器失败     )-->由门店自己控制该标志 对于A服务器: (0=没接收完成 1=已接收完毕 2=已接收完毕但:超时门店上传A服务器失败     )-->由门店控制该标志 对于B服务器: (0=没接收完成 1=已接收完毕 2=已接收完毕但:超时门店上传A服务器失败     )-->由B服务器自己控制该标志'''; END IF; END $$;
