DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'transferdata') THEN EXECUTE 'COMMENT ON TABLE transferdata IS ''保存门店的上传数据表'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'transferdata' AND column_name = 'tdstatus') THEN EXECUTE 'COMMENT ON COLUMN transferdata.tdstatus IS ''数据状态: -10=数据接收失败, 0=保留, 1=上传完成可以导出, 2=已经导出完成可以删除'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'transferdata' AND column_name = 'prefixtable') THEN EXECUTE 'COMMENT ON COLUMN transferdata.prefixtable IS ''空 或 WHOLE_ 或 SUM_ = 上传销售数据(DATA1=CHECKS,DATA2=CHKDETAIL,DATA3=CHECKRST,DATA4=ICCARD_CONSUME_INFO,DATA5=ABUYER) PACK 或 PACK WHOLE_ 或 PACK SUM_ = 上传销售数据(DATA1=没压缩的数据包,DATA2=压缩的数据包) ENDOFTIME=已完成上传RESERVE3指定日期的数据 CNFFROMREMOTE=从远端传过来的配置数据(DATA1=传过来的压缩配置数据) CNFTOREMOTE=需要发送到远端的配置数据(DATA1=要传到远端的压缩配置数据)'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'transferdata' AND column_name = 'ziptype') THEN EXECUTE 'COMMENT ON COLUMN transferdata.ziptype IS '' 空=之前没有上传过数据, 0=普通的ZLib, 1=VclZip里面的Zlib, 2=VclZip里面的zip, 3=不压缩, 4=gZipCompress 10=经过MIME64编码 12=经过MIME64编码 和 VclZip里面的zip压缩'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'transferdata' AND column_name = 'packtype') THEN EXECUTE 'COMMENT ON COLUMN transferdata.packtype IS ''0 =WHOLE_ 或 SUM_ 单条上传销售数据(DATA1=CHECKS,DATA2=CHKDETAIL,DATA3=CHECKRST,DATA4=ICCARD_CONSUME_INFO,DATA5=ABUYER) 1 =PACK 或 PACK WHOLE_ 或 PACK SUM_ = 上传销售数据(DATA1=没压缩的数据包,DATA2=压缩的数据包) 2 =ENDOFTIME=已完成上传RESERVE3指定日期的数据 3 =CNFFROMREMOTE=从远端传过来的配置数据(DATA1=传过来的压缩配置数据) 4 =CNFTOREMOTE=需要发送到远端的配置数据(DATA1=要传到远端的压缩配置数据)'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'transferdata' AND column_name = 'recordcount') THEN EXECUTE 'COMMENT ON COLUMN transferdata.recordcount IS ''打包的记录数据'''; END IF; END $$;
