DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'transferdata_buffer' AND column_name = 'tdstatus') THEN EXECUTE 'COMMENT ON COLUMN transferdata_buffer.tdstatus IS ''Buffer数据状态: -10=远端数据接收失败, 0=需要上传, 1=上传完成'''; END IF; END $$;
