DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'transferdata_buffer' AND column_name = 'packtype') THEN EXECUTE 'COMMENT ON COLUMN transferdata_buffer.packtype IS ''0 =WHOLE_ 或 SUM_ 单条上传销售数据(DATA1=CHECKS,DATA2=CHKDETAIL,DATA3=CHECKRST,DATA4=ICCARD_CONSUME_INFO,DATA5=ABUYER) 1 =PACK 或 PACKWHOLE_ 或 PACKSUM_ = 成批上传销售数据(DATA1=没压缩的数据包,DATA2=压缩的数据包) 2 =ENDOFTIME=已完成上传RESERVE3指定日期的数据 3 =CNFFROMREMOTE=从远端传过来的配置数据(DATA1=传过来的压缩配置数据) 4 =CNFTOREMOTE=需要发送到远端的配置数据(DATA1=要传到远端的压缩配置数据)'''; END IF; END $$;
