DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'midetail_campaignactivity' AND column_name = 'act_type') THEN EXECUTE 'COMMENT ON COLUMN midetail_campaignactivity.act_type IS ''活动类型 注意：1.需要添加到门店的root/PythonCode/hq/hq_GetShopConfigData.py 查找关键字 act_type 2.需要添加到门店存储过程send_campaignactivity_to_buyslgivesl 查找关键字 act_type 0=满量特卖活动 1=折扣特卖活动(每个品种都有自己的折扣和单价) 2=送券优惠活动 3=积分倍增活动 4=积分清零活动 5=加收服务费活动'''; END IF; END $$;
