DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'midetail_campaignactivity' AND column_name = 'act_fullgive_discountamount') THEN EXECUTE 'COMMENT ON COLUMN midetail_campaignactivity.act_fullgive_discountamount IS ''满量特卖-折扣 10%(价格=10%) 10(价格=10元) -10%(减去10%) -10(减去10元)'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'midetail_campaignactivity' AND column_name = 'act_fullgive_discountfrom') THEN EXECUTE 'COMMENT ON COLUMN midetail_campaignactivity.act_fullgive_discountfrom IS ''满量特卖-单价控管(即：当混搭的品种有不同价格时对那个品种进行打折) 0=低价优先（满量与优惠是相同的品种） 1=高价优先（满量与优惠是相同的品种） 2=特卖套餐（根据“优惠品种”对指定品种的数量进行折扣） --优惠品种设置在"MIDETAIL_CampaignActivity_givemenuitems" 3=红绿配（满量与优惠分别是不同的品种）  --优惠品种设置在"MIDETAIL_CampaignActivity_givemenuitems" 4=买啥优惠啥（买品种A，只能优惠品种A）'''; END IF; END $$;
