DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'midetail_campaignactivity' AND column_name = 'act_rule') THEN EXECUTE 'COMMENT ON COLUMN midetail_campaignactivity.act_rule IS '' { --act_type 为"2=送券优惠活动"生效，表示送券活动规则 "rule_givecoupons": [{ "ruleid": "2",                          //规则ID  2=关联实体卡时送优惠券 3=关注公众时送优惠券 4=充值送优惠券 5=完善资料送券 6=会员生日送券 7=会员筛选送券 8=会员消费满送券 9=抢购优惠券活动'''; END IF; END $$;
