DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'iccard_consume_info') THEN EXECUTE 'COMMENT ON TABLE iccard_consume_info IS ''用于出ICCard消费信息报表'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'iccard_consume_info' AND column_name = 'icinfo_consumetype') THEN EXECUTE 'COMMENT ON COLUMN iccard_consume_info.icinfo_consumetype IS ''类型: -1=无效充值 0=VIP卡消费 1=VIP卡充值 2=修改IC卡消费金额 3=积分累计记录 4=积分扣除记录 和 积分付款消费(对应TENDERMEDIA的RESERVE3的1) 5=积分换礼品 6=积分折现付款(对应TENDERMEDIA的RESERVE3的21, 22, 23, 24, 25) 7=直接修改总积分  //'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'iccard_consume_info' AND column_name = 'icinfo_amount') THEN EXECUTE 'COMMENT ON COLUMN iccard_consume_info.icinfo_amount IS ''消费金额("消费") 充值金额("充值") 添加的消费数("修改IC卡消费金额") 添加的积分数("积分累计") 消费的积分数("积分消费") 换礼品的积分数("积分换礼品") 消费金额("积分折现付款")  lzm add 【2011-07-21】 添加的总积分("直接修改总积分") //'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'iccard_consume_info' AND column_name = 'icinfo_balance') THEN EXECUTE 'COMMENT ON COLUMN iccard_consume_info.icinfo_balance IS ''卡内余额("消费") 卡内余额("充值") 卡内剩余消费合计("修改IC卡消费金额"后的卡内余额) 卡内剩余积分("积分累计") 卡内剩余积分("积分消费") 卡内剩余积分("积分换礼品") 卡内积分折现余额("积分折现付款")  lzm add 【2011-07-21】 卡内剩余的总积分("直接修改总积分") //'''; END IF; END $$;
