DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'export_checkrst' AND column_name = 'scpayclass') THEN EXECUTE 'COMMENT ON COLUMN export_checkrst.scpayclass IS ''支付类型 讯联 PURC:下单支付 VOID:撤销 REFD:退款 INQY:查询 PAUT:预下单 VERI:卡券核销 翼富 PURC:下单支付 VOID:撤销 INQY:查询 CLOS:关闭订单 智能设备 SIGN:签到'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'export_checkrst' AND column_name = 'scpaychannel') THEN EXECUTE 'COMMENT ON COLUMN export_checkrst.scpaychannel IS ''支付渠道 讯联 ALP:支付宝支付 WXP:微信支付 翼富 ALP:支付宝支付 WXP:微信支付 APP:苹果付 SXP:三星付 UNP:银联 OTP:第三方支付 WXALP:微信或支付宝自动识别 智能设备 BBPOS 香港的智能支付设备 KPAY 香港的智能支付设备'''; END IF; END $$;
