DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'prnpreview') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.prnpreview IS ''是否需要预览 0=不需要预览 和 设置的打印单状态是1(即:DOCMAIN表的DOCSATE) 1=现在需要打印 1=需要预览 和 设置的打印单状态是0(即:DOCMAIN表的DOCSATE) 1=现在需要打印  【以下是用于结账内的入单】 2=不需要预览 和 设置的打印单状态是0(即:DOCMAIN表的DOCSATE) 0=新打印单 3=需要预览 和 设置的打印单状态是0(即:DOCMAIN表的DOCSATE) 0=新打印单'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'prnstatus') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.prnstatus IS ''处理状态 0=新的帐单 1=正在处理 2=处理成功 3=处理成功但没找到打印内容 4=现需要处理 5=打印超时 10=处理失败'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'prndoctype') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.prndoctype IS ''0=报表和杂项 1=厨房打印(催单,厨房单) 2=转台(从PRN_DOCDETAIL提取打印详细) 3=弹钱箱 4=转台-需要通知出品部(从PRN_CHKDETAIL提取打印详细) //'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'atablesid') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.atablesid IS ''对应 ATABLES 中的 ATABLESID'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reference') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reference IS ''外送单的相关信息 如果是ICCARD充值则记录该ICCARD的信息"ICCARD:(8762519301)0000->0000" 如果MODEID=盘点单，记录盘点的批号 或 用于总部的数据整理：''''S1''''=按用餐方式合计整天的营业数据到一张帐单'''; END IF; END $$;
