DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'ftotal') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.ftotal IS '' 应付金额＝SUBTOTAL-DISCOUNT(CHECK+ITEM)+SERVICECHARGE(自动+附加)+税'''; END IF; END $$;
