DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'checktotal') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.checktotal IS ''已付款金额'''; END IF; END $$;
