DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve2') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve2 IS ''0=有效单据，1=无效单据【ADD OR SPLIT(合单,分单前或作废的单据,即:该单据为作废单不能参与计算或运作,报表也不包含该帐单)】 2=作废'''; END IF; END $$;
