DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve02') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve02 IS ''磁卡或IC卡时：记录会员卡对应的''''EMPID''''  不是IDVALUE 微信会员卡时：为空字符串暂时没用【之前：记录扩展信息 //'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve03') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve03 IS ''折扣【5种VIP卡和第四种打折方式】: "/[状态]/[0或1或2]/[%或现金的数目或DISCOUNTID]"， N表示nil 【状态:全部为0】/【 %为0, 现金为1, 折扣编号为2】'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve04') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve04 IS ''折扣【餐后点饮料、原品续杯、非原品续杯】 "/[状态]/[0或1或2]/[%或现金的数目或DISCOUNTID]" N表示nil 【状态: 纪录0或空:不打折，1：餐后点饮料、2：原品续杯、3：非原品续杯】/【 %为0, 现金为1, 折扣编号为2】'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve05') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve05 IS ''假帐 1=新的已结单, 由1更新到2=触发数据库触发器进行假帐处理并变为3, 3=处理完毕, 4=ReOpen的单据. (经过DBToFile程序后,由4更新到3,由1更新到2)  对于EXPORT_CHECKS表:1=新的已结单 2=导出到接口库成功 3=生成冲红单到接口成功'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve11') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve11 IS ''jaja 记录预定人使用时Table5相应记录的id值'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve12') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve12 IS ''先保留没有启用【之前：jaja 记录---挂单 PutUpBillClickEvent()已停用 ---  0或null:不是挂单; 1:挂单】'''; END IF; END $$;
