DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve16') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve16 IS ''CASHIERNAME收银员名称'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve17') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve17 IS ''ITEMDISCOUNT品种折扣合计'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve18') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve18 IS ''上传数据到总部: 1=新的已结单, 3=处理完毕, 4=ReOpen的单据 或 需要全部重传, 5=账单不完整不需要上传总部 6=日结时修改了账单日期需要重新上传或作废账单需要重传【旧：0或空=新的已结单没有上传，1=成功【再旧：记录BackUp成功=1】】'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve19') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve19 IS ''上次上传数据到总部的压缩方法【旧：记录MIS成功=1】: 空=之前没有上传过数据, 0=普通的ZLib, 1=VclZip里面的Zlib, 2=VclZip里面的zip, 3=不压缩, 10=经过MIME64编码  12=经过MIME64编码 和 VclZip里面的zip压缩'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'prn_checks' AND column_name = 'reserve20') THEN EXECUTE 'COMMENT ON COLUMN prn_checks.reserve20 IS ''帐单类型(20050805) 营业报表只统计"普通账单"的记录（即：RESERVE20='''''''' or RESERVE20=''''0'''' or RESERVE20 is NULL）  0或空=普通帐单 1=IC卡充值帐单 2=换礼品扣除会员券或积分(在功能 MinusCouponClickEvent 里设置)帐单 3=全VOID单 4=餐券入店记录-没做 5=从钱箱提取现金的帐单 6=收银交班帐单 7=客户记账后的还款帐单'''; END IF; END $$;
