DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'new_empclass' AND column_name = 'reserve03') THEN EXECUTE 'COMMENT ON COLUMN new_empclass.reserve03 IS ''卡的明细类型 0=普通员工磁卡 1=高级员工磁卡（有打折功能） 2=客户VIP磁卡（如果是：直接刷卡付款则金额记录在中心数据库；否则不记录在数据库,有打折功能,有会员积分功能） 3=客户IC卡（金额纪录在中心数据库,有打折功能,有会员积分功能） 4=客户IC卡（金额纪录在IC卡上,有打折功能,有会员积分功能，消费金额记录在IC卡上） ?5=客户IC卡（金额纪录在IC卡上,有打折功能,有会员积分功能，消费金额记录在IC卡上）'''; END IF; END $$;
