DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'new_empclass' AND column_name = 'grantstr') THEN EXECUTE 'COMMENT ON COLUMN new_empclass.grantstr IS ''用户权限,拥有的权限用逗号分割 [ 位置1:领料单是否允许修改单价 0=否1=是 位置2:退料单是否允许修改单价 0=否1=是 位置3:直拨单的供应商编号对应的单价是否允许修改 (格式:  01;02=1 代表:只允许编号为01或02的供应商修改单价 01=1    代表:只允许编号为01的供应商时修改单价) 位置4:进货单的供应商编号对应的单价是否允许修改 (格式:  01;02=1 代表:只允许编号为01或02的供应商修改单价 01=1    代表:只允许编号为01的供应商时修改单价) ]'''; END IF; END $$;
