DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'hq_issue_tendermedia' AND column_name = 'reserve2') THEN EXECUTE 'COMMENT ON COLUMN hq_issue_tendermedia.reserve2 IS ''付款类型: 对应 LISTCONTENT 的 LCLAID=21 ''''0''''=现金, ''''1''''=CGC(赠券) 【在系统汇总报表，中根据该类型分别统计“现金”和“赠券”的消费金额】'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'hq_issue_tendermedia' AND column_name = 'reserve3') THEN EXECUTE 'COMMENT ON COLUMN hq_issue_tendermedia.reserve3 IS '' 0:空:普通 1:会员券(即:积分)的付款方式【会员可以有消费积分，根据消费积分可以转换为会员券】 2:用礼券付款【需要记录礼券编号】(v5.2之后的礼券付款标志) 3:"记帐"(CHECKRST.RESERVE04记录ABUYER.BUYERID) 4:信用卡刷卡(CHECKRST.VISACARD_CARDNUM和CHECKRST.VISACARD_BILLNUM分别记录卡号和刷卡的帐单号) 5:订金 6:餐券付款【需要录入券额和数量】 7:银行积分付款 lzm add 【2009-06-21】 8:客户记账后的现金还款 lzm add 【2009-08-14】  9:IC卡记录消费金额的消费方式 10:IC卡充值的付款方式(金额数保存在IC卡上)  **用于直接输入卡号付款,根据卡号提取付款的BCID,ANUMBER**  11:A卡的付款方式                           **用于直接输入卡号付款,根据卡号提取付款的BCID,ANUMBER** 12:B卡的付款方式                           **用于直接输入卡号付款,根据卡号提取付款的BCID,ANUMBER** 13:C卡的付款方式                           **用于直接输入卡号付款,根据卡号提取付款的BCID,ANUMBER** 14:D卡的付款方式                           **用于直接输入卡号付款,根据卡号提取付款的BCID,ANUMBER** 15:E卡的付款方式                           **用于直接输入卡号付款,根据卡号提取付款的BCID,ANUMBER**  16:直接修改总积分付款  //'''; END IF; END $$;
