DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'hq_issue_empclass' AND column_name = 'accesslevel') THEN EXECUTE 'COMMENT ON COLUMN hq_issue_empclass.accesslevel IS '' 0-Admin管理权限, 1-Normal普通权限, 2-cFreeRight, 3-咨客开单, 4-桑那钟房, 5-技师, 6-客房管理员 7-服务员或吧女,用于推销酒水或其它品种的提成 8-划单员  等于以下值时，对应Discount表的:LIDU(凹度):可以知道该用户的折扣率 11=A卡 12=B卡 13=C卡 14=D卡 15=E卡'''; END IF; END $$;
